mapper.select:
SELECT rest_type_id AS restTypeId,
       ROUND(COUNT(*) * 100.0 / (
           SELECT COUNT(*) FROM rest_logs
           WHERE `쉼표번호` = #{쉼표번호} AND deleted = 0
             AND DATE_FORMAT(start_time, '%Y-%m') = #{yearMonth}
       ), 1) AS ratio
FROM rest_logs
WHERE `쉼표번호` = #{쉼표번호} AND deleted = 0
  AND DATE_FORMAT(start_time, '%Y-%m') = #{yearMonth}
GROUP BY rest_type_id

mapper.update:
UPDATE monthly_stats
SET total_rest_minutes = #{totalRestMinutes}, type_ratio_json = #{typeRatioJson},
    avg_emotion_score = #{avgEmotionScore}, record_count = #{recordCount}
WHERE id = #{id}
